const input = $input.first().json;
const product = input.product || {};
const platform = input.platform || 'instagram';
const prompt = `Write a ${platform} product caption for:
Title: ${product.title}
Description: ${product.description || ''}
Price: ₹${product.price || 0}
Tone: ${input.tone || 'engaging'}
Return JSON only: { "caption": "...", "hashtags": ["#tag1"], "fullText": "caption with hashtags" }`;
return [{ json: { ...input, prompt } }];

const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(raw.replace(/```json\n?|```/g, '').trim()); } catch { parsed = { caption: raw, hashtags: [], fullText: raw }; }
return [{ json: { caption: parsed.caption, hashtags: parsed.hashtags || [], fullText: parsed.fullText || parsed.caption } }];
